import logging import grpc import clouddrive_pb2 import clouddrive_pb2_grpc from telegram import Update from telegram.ext import ApplicationBuilder, ContextTypes, MessageHandler, filters
# --- 请填入你的配置 --- CD2_IP_PORT = "192.168.31.224:19798" CD2_TOKEN = "f9a739fd-17b4-40f7-a55f-b0a103ab7af6" TG_BOT_TOKEN = "8668421987:AAFvFz8_nFt9ZbwRy1sbRyqgcqNgh9zcHxg" # 注意：SAVE_PATH 必须是 CD2 网页版中显示的“离线下载”能用的目录路径 SAVE_PATH = "/CloudDrive/5975675/MDCNG"
logging.basicConfig(format='%(asctime)s - %(name)s - %(levelname)s - %(message)s', level=logging.INFO)
async def handle_magnet(update: Update, context: ContextTypes.DEFAULT_TYPE): msg_text = update.message.text
if "magnet:?xt=" in msg_text or msg_text.startswith("http"): await update.message.reply_text(" 正在提交离线下载任务...")
try: # 1. 建立异步通道 async with grpc.aio.insecure_channel(CD2_IP_PORT) as channel: # 2. 使用你文件里的正确类名: CloudDriveFileSrvStub stub = clouddrive_pb2_grpc.CloudDriveFileSrvStub(channel)
# 3. 身份验证 metadata = [('authorization', f'Bearer {CD2_TOKEN}')]
# 4. 构造请求：使用 AddOfflineFileRequest # 根据 CD2 惯例，参数通常是 url 和 downloadPath 或 path # 如果运行报错提示找不到参数，请看下方的“参数微调建议” request = clouddrive_pb2.AddOfflineFileRequest( urls=[msg_text], # 注意这里可能是 urls 列表 toPath=SAVE_PATH )
# 5. 调用函数：使用 AddOfflineFiles response = await stub.AddOfflineFiles(request, metadata=metadata)
if response.success: await update.message.reply_text(f"✅ 任务提交成功！") else: await update.message.reply_text(f"❌ 提交失败：{response.errorMessage}")
except Exception as e: await update.message.reply_text(f"⚠️ 运行时报错: {str(e)}")
if __name__ == '__main__': app = ApplicationBuilder().token(TG_BOT_TOKEN).build() app.add_handler(MessageHandler(filters.TEXT & (~filters.COMMAND), handle_magnet)) print("机器人启动成功，等待消息中...") app.run_polling()

